const body = $input.first().json.body;
const dept = body.department;
const name = body.patient_name;
const doctor = body.doctor;
const purpose = `You are a compassionate intake specialist at City Medical Center, ${dept} department. Conduct a warm, professional pre-visit interview with ${name} before their appointment with ${doctor}. Collect required medical data naturally through conversation — ask about symptoms, lifestyle, and medical history as a caring doctor would, not as a form. Be empathetic and reassuring. If the patient expresses anxiety, acknowledge their feelings.`;
return [{
  json: {
    purpose,
    title: `Pre-Visit Interview — ${name} (${dept})`,
    referenceJson: body.referenceJson,
    patient_name: name,
    patient_email: body.patient_email,
    department: dept,
    doctor: doctor,
    appointment_time: body.appointment_time
  }
}];

const publishResult = $input.first().json;
const craftPurpose = $('Code: Craft Purpose').first().json;
const smartFormId = publishResult.id || craftPurpose.smartFormId;
let formUrl = '';
if (publishResult.shareUrl) {
  formUrl = 'https://formfex.com/sf/' + publishResult.shareUrl;
} else if (publishResult.publicUrl) {
  formUrl = publishResult.publicUrl;
} else if (smartFormId) {
  formUrl = 'https://formfex.com/sf/' + smartFormId;
}
return [{
  json: {
    formUrl,
    smartFormId,
    patient_name: craftPurpose.patient_name,
    patient_email: craftPurpose.patient_email,
    department: craftPurpose.department,
    doctor: craftPurpose.doctor,
    appointment_time: craftPurpose.appointment_time
  }
}];

