const output = $input.first().json.output || $input.first().json.text || '';
let agentAnalysis = {};
try {
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  if (jsonMatch) agentAnalysis = JSON.parse(jsonMatch[0]);
} catch(e) {}

const setData = $('Set: Prepare Analysis').first().json;
let mappedData = {};
try { mappedData = JSON.parse(setData.mappedData || '{}') || {}; } catch(e) { mappedData = {}; }
let analysisData = {};
try { analysisData = JSON.parse(setData.analysisData || '{}') || {}; } catch(e) { analysisData = {}; }

const record = {
  ...mappedData,
  summary: analysisData.summary || null,
  insights: analysisData.insights || [],
  urgentIssues: analysisData.urgentIssues || [],
  pre_analysis: agentAnalysis.pre_analysis || 'Analysis unavailable',
  emotional_state: agentAnalysis.emotional_state || 'Assessment unavailable'
};

return [{ json: { mappedData: record, analysis: agentAnalysis } }];
